  ('cpa-moex-01390', 'cpa', 'cpa-moex-103-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '平衡計分卡包括四個績效評估構面，其中「內部程序面」所強調的重點是：', '["建立售後服務程序，以提升顧客滿意度", "建立適當的獎酬制度以激勵員工", "提升獲利績效", "強化資訊系統能力，以提供決策資訊"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "931ef34bb028", "answer_pdf_sha1": "0115394f7ee8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
